#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int Q;
    // Process test cases until EOF
    while (scanf("%d", &Q) == 1) {
        int capacity = 2;
        int *arr = (int*)malloc(capacity * sizeof(int));
        int sz = 0;
        char op[10];
        for (int i = 0; i < Q; ++i) {
            scanf("%s", op);
            if (strcmp(op, "add") == 0) {
                int x; scanf("%d", &x);
                if (sz == capacity) {
                    capacity *= 2;
                    arr = (int*)realloc(arr, capacity * sizeof(int));
                }
                arr[sz++] = x;
            } else if (strcmp(op, "get") == 0) {
                int idx; scanf("%d", &idx);
                printf("%d\n", arr[idx]);
            } else if (strcmp(op, "size") == 0) {
                printf("%d\n", sz);
            } else if (strcmp(op, "print") == 0) {
                for (int j = 0; j < sz; ++j) {
                    if (j) printf(" ");
                    printf("%d", arr[j]);
                }
                printf("\n");
            }
        }
        free(arr);
    }
    return 0;
}

