#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    long long Q;
    while (cin >> Q) {
        vector<int> data;
        data.reserve(2);
        int sz = 0;
        string op;
        for (long long i = 0; i < Q; ++i) {
            cin >> op;
            if (op == "add") {
                int x; cin >> x;
                if (sz == (int)data.size()) data.push_back(0); // ensure capacity
                if (sz == (int)data.capacity()) {
                    data.reserve(data.capacity() * 2);
                }
                if (sz < (int)data.size()) data[sz] = x; else data.push_back(x);
                ++sz;
            } else if (op == "get") {
                int idx; cin >> idx;
                cout << data[idx] << '\n';
            } else if (op == "size") {
                cout << sz << '\n';
            } else if (op == "print") {
                for (int j = 0; j < sz; ++j) {
                    if (j) cout << ' ';
                    cout << data[j];
                }
                cout << '\n';
            }
        }
    }
    return 0;
}

