import java.io.*;
import java.util.*;

public class Main {
    private static class MyArrayList {
        private int[] data;
        private int size;
        MyArrayList() {
            data = new int[2];
            size = 0;
        }
        void add(int v) {
            if (size == data.length) resize();
            data[size++] = v;
        }
        int get(int idx) { return data[idx]; }
        int size() { return size; }
        void print(PrintWriter out) {
            for (int i = 0; i < size; ++i) {
                if (i > 0) out.print(' ');
                out.print(data[i]);
            }
            out.println();
        }
        private void resize() {
            int[] nd = new int[data.length * 2];
            System.arraycopy(data, 0, nd, 0, data.length);
            data = nd;
        }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        PrintWriter out = new PrintWriter(new BufferedWriter(new OutputStreamWriter(System.out)));
        String line;
        while ((line = br.readLine()) != null) {
            line = line.trim();
            if (line.isEmpty()) continue;
            int Q = Integer.parseInt(line);
            MyArrayList list = new MyArrayList();
            for (int i = 0; i < Q; ++i) {
                String cmdLine = br.readLine();
                String[] parts = cmdLine.split(" ");
                switch (parts[0]) {
                    case "add":
                        list.add(Integer.parseInt(parts[1]));
                        break;
                    case "get":
                        out.println(list.get(Integer.parseInt(parts[1])));
                        break;
                    case "size":
                        out.println(list.size());
                        break;
                    case "print":
                        list.print(out);
                        break;
                }
            }
        }
        out.flush();
    }
}

