import sys

def process_case(lines, idx):
    Q = int(lines[idx])
    idx += 1
    data = [0] * 2
    sz = 0
    out_lines = []
    for _ in range(Q):
        parts = lines[idx].split()
        idx += 1
        if parts[0] == 'add':
            x = int(parts[1])
            if sz == len(data):
                data.extend([0] * len(data))  # double capacity
            data[sz] = x
            sz += 1
        elif parts[0] == 'get':
            out_lines.append(str(data[int(parts[1])]))
        elif parts[0] == 'size':
            out_lines.append(str(sz))
        elif parts[0] == 'print':
            out_lines.append(' '.join(str(data[i]) for i in range(sz)))
    return idx, out_lines

def main():
    lines = [line.rstrip('\n') for line in sys.stdin if line.strip()!='']
    idx = 0
    output = []
    while idx < len(lines):
        idx, out = process_case(lines, idx)
        output.extend(out)
    sys.stdout.write('\n'.join(output))

if __name__ == "__main__":
    main()

