  const Q = parseInt(input[idx].trim(), 10);
  idx++;
  let data = new Array(2);
  let sz = 0;
  for (let i = 0; i < Q; i++) {
    const parts = input[idx].trim().split(' ');
    idx++;
    const cmd = parts[0];
    if (cmd === 'add') {
      const val = parseInt(parts[1], 10);
      if (sz === data.length) {
        const nd = new Array(data.length * 2);
        for (let j = 0; j < data.length; j++) nd[j] = data[j];
        data = nd;
      }
      data[sz++] = val;
    } else if (cmd === 'get') {
      const pos = parseInt(parts[1], 10);
      output.push(String(data[pos]));
    } else if (cmd === 'size') {
      output.push(String(sz));
    } else if (cmd === 'print') {
      output.push(data.slice(0, sz).join(' '));
    }
  }
}
